@startuml
skinparam packageStyle rectangle

package "businessRules" {
    frame Entity <<frame>> {
        class User {
            email: string
            roles: array
            password: string
            firstname: string
            lastname: string
        }

        note right of User : C

        class Post {
            title: string
            description: string
            createdAt: DateTimeInterface
        }

        note left of Post : C

        class Picture {
            name: string
            url: string
        }

        note top of Picture : C

        ' Relationships - using composition to match diamond symbols in original
        User *-- Post : One To Many\nMany
        Post *-- Picture : One To Many\nMany
    }
}
@enduml
